var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"내가…… 무슨 짓을 저지른 거지? 내가 대체 왜 사람들을…?","JPN":"私は……何をしたの？　いったいどうして私が人たちを……？","ENG":"What... have I done...? To all those people...","TWN":"我…… 我到底做了什麼？我爲什麼會人們…？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"웁……! 우웁……!","JPN":"うっ……！　おえっ……！","ENG":"*Retch*","TWN":"噁……！噁噁……！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"이상해……. 어서 성유물을 찾아서… 형제들에게 돌아가야…","JPN":"おかしい……早く聖遺物を探して……兄弟のもとに戻らないと……","ENG":"Something's weird... I need to find the Holy Relic and... get back to my brothers...","TWN":"不對勁……要趕快找到聖遺物……回到兄弟們的身邊。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"아아, 시시하네. 제일 재밌을 때 엄살 떨면서 도망치다니.","JPN":"ああ、つまんないわ。一番面白い時に後ろ向きになって逃げ出すなんて。","ENG":"Ugh... Boring. You're really going to run away when the best part’s just about to begin?","TWN":"啊啊，真是無聊，竟然在最有趣的時候跑掉。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"…뭐, 뭐야? 방금 누가 말한 거야?","JPN":"……な、何？　今誰が喋ったの？","ENG":"W-what? Who's there?","TWN":"…什…什麼？剛才是誰在說話？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"벌써 잊었어? 네가 날 깨웠잖니?","JPN":"もう忘れたの？　あんたがあたしを起こしたんじゃない。","ENG":"Did you already forget? You woke me up, remember?","TWN":"這麼快就忘了嗎？不是你把我叫醒的嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"엘리시움……?","JPN":"エリシウム……？","ENG":"Elysium...?","TWN":"愛樂組織……？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아냐, 아냐, 아냐! 그럴 리 없어! 넌 큐리안에게 격퇴당했잖아!","JPN":"違う、違う、違う！　そんなわけない！　あなたはキュリアンにやられたでしょ！","ENG":"No, no, no! There's no way! You were killed by Curian!","TWN":"不，不，不！不可能！庫里安明明已經擊敗你！"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"왜 이래. 내 핵을 깨워 준 건 너잖아.","JPN":"何言ってるの。あたしの核を目覚めさせたのはあんたでしょ？","ENG":"What do you mean? You're the one who woke up my core.","TWN":"幹嘛這樣，就是你喚醒我的核心的。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"상대가 관리국 녀석들이었으면 큰일날 뻔했지. 그 때는 놈이 우릴 잘 몰라서 다행이었어.","JPN":"相手が管理局のやつらだったらやばかったわ。あの時、あいつはあたしたちのことをよく知らなくて助かっちゃった。","ENG":"It would've been a disaster if they were from the Administration. Thank the heavens they don't know much about us.","TWN":"要對方是管理局的人可就大事不妙，幸好那時候他不認識我們。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"내가… 널 깨웠다고?","JPN":"私が……あなたを目覚めさせた？","ENG":"I... woke you up?","TWN":"我… 喚醒你？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그럼 형제들이 가르쳐 준 방법이 정말 <color=#ffd34c>억제법</color>인 줄 알았어?","JPN":"それじゃ、兄弟が教えた方法が本当に<color=#ffd34c>抑制法</color>だと思ってたの？","ENG":"Did you really think that the <color=#ffd34c>suppression method</color> your brothers taught you would work?","TWN":"難道你以為兄弟們教你的方法真的是<color=#ffd34c>鎮壓之法</color>嗎？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"아아, 불쌍한 한나. 그런 빈말만 믿고 날 이용할 수 있을 거라고 착각하다니.","JPN":"ああ、かわいそうなハンナ。あんな嘘を信じてあたしを利用できると勘違いしてたなんて。","ENG":"Oh my. Poor Hanna... How foolish of you to think you could control me so easily.","TWN":"啊啊，可憐的漢娜，竟然相信那種口說無憑的話，還以為可以利用我。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"도……. 도로 가져 가…….","JPN":"も……持っていって……","ENG":"T-take... Take it back...!","TWN":"拿……拿回去吧……"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"이딴 힘, 그냥 가져가 버려! 난 이런 힘을 원한 게 아니야! 내가 원하던 건……!","JPN":"こんな力、持っていって！　こんな力がほしかったわけじゃない！　私がほしかったのは……！","ENG":"I don't want your powers! This isn't what I wanted! I just wanted to...!","TWN":"這股力量，你拿去吧！我沒有想要這種力量！我想要的是……！"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"오. 오. 오. 그 이상 말하지 않아도 돼.","JPN":"お。お。お。それ以上は話さなくていいわ。","ENG":"Oh. Now. Now. Don't say that.","TWN":"喔，喔，喔，不必說了。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"세상을 지킨답시고 죽을 고생을 했는데 아무도 안 알아 주는 게 싫었던 거잖아?","JPN":"世界を守るって死ぬ気で頑張ったのに、誰もわかってくれないのがイヤだったんでしょ？","ENG":"Don't you hate it when people don't understand how hard you worked to try to protect this world?","TWN":"你不是很生氣嗎？為了守護世界吃了那麼多苦，卻沒人安慰你。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_MEDIUS","text":{"KOREA":"그래. 갚아 줘야지. 너희들을 희생시킨 자들에게.","JPN":"そう。仕返ししないとね。あんたたちに犠牲を強いてきたやつらに。","ENG":"Yes. It's time they knew. To all those who sacrificed you all.","TWN":"沒錯，當然要對那些犧牲你們的人加倍奉還囉。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_MEDIUS","face":"UNIT_IDLE"}}}}]`);export{e as default};